const locations = [
  { location: 'Portugal', query: 'promotor imobiliário property developer incorporador real estate development construction', maxItems: 30 },
  { location: 'Lisbon Metropolitan Area', query: 'real estate development investment promotion construction', maxItems: 20 },
  { location: 'Porto', query: 'promotor imobiliário property developer construção promoção imobiliária', maxItems: 15 },
  { location: 'Algarve', query: 'real estate developer property development resort construction', maxItems: 15 }
];

const now = new Date();
const weekNum = Math.ceil((((now - new Date(now.getFullYear(),0,1)) / 86400000) + new Date(now.getFullYear(),0,1).getDay() + 1) / 7);
const rotationIndex = weekNum % locations.length;
const config = locations[rotationIndex];

const weekLabel = 'W' + String(weekNum).padStart(2, '0');
const runDate = now.toISOString().split('T')[0];

return [{ json: {
  location: config.location,
  query: config.query,
  maxItems: config.maxItems,
  weekLabel: weekLabel,
  runDate: runDate,
  rotationIndex: rotationIndex
}}];

const input = $input.all();
const config = $('Location Rotation').first().json;
const results = [];
const seen = new Set();

for (const item of input) {
  const d = item.json;
  const name = ((d.firstName || '') + ' ' + (d.lastName || '')).trim();
  const url = d.linkedinUrl || '';

  if (!name || !url) continue;
  if (seen.has(url)) continue;
  seen.add(url);

  const headline = d.headline || '';
  const about = d.about || '';
  const loc = d.location?.linkedinText || d.location?.parsed?.text || '';
  const connections = d.connectionsCount || 0;
  const followers = d.followerCount || 0;

  const exp = d.experience || [];
  const currentExp = exp[0] || {};
  const company = currentExp.companyName || '';
  const title = currentExp.position || '';
  const companyUrl = currentExp.companyLinkedinUrl || '';

  const expYears = exp.reduce((sum, e) => {
    const start = e.startDate?.year || 0;
    const end = e.endDate?.year || new Date().getFullYear();
    return sum + (end - start);
  }, 0);

  const skills = (d.skills || []).map(s => s.name || s).slice(0, 10);
  const hasWebsite = (d.companyWebsites || []).length > 0;
  const website = hasWebsite ? d.companyWebsites[0].url || d.companyWebsites[0].domain || '' : '';

  const lastPost = '';

  results.push({ json: {
    nome: name,
    headline: headline,
    about: about.substring(0, 500),
    empresa: company,
    cargo: title,
    companyUrl: companyUrl,
    linkedinUrl: url,
    location: loc,
    connections: connections,
    followers: followers,
    expYears: expYears,
    skills: skills.join(', '),
    website: website,
    lastPost: lastPost,
    weekLabel: config.weekLabel,
    runDate: config.runDate,
    source: 'LinkedIn'
  }});
}

if (results.length === 0) {
  return [{ json: { _skip: true, _msg: 'No valid profiles found' } }];
}

return results;

const items = $input.all();
if (items[0]?.json._skip) return items;

const token = '***REDACTED***';
let existingUrls = new Set();
try {
  let offset = '';
  while (true) {
    const url = 'https://api.airtable.com/v0/appHlW68vIgSzS8BX/tblfEtNAVuXRZdxW9?fields%5B%5D=LinkedIn+URL&pageSize=100' + offset;
    const resp = await fetch(url, { headers: { 'Authorization': 'Bearer ' + token } });
    const data = await resp.json();
    for (const rec of (data.records || [])) {
      const u = rec.fields?.['LinkedIn URL'] || '';
      if (u) existingUrls.add(u);
    }
    if (!data.offset) break;
    offset = '&offset=' + data.offset;
  }
} catch(e) {}

const newLeads = items.filter(i => !existingUrls.has(i.json.linkedinUrl));
if (newLeads.length === 0) return [{ json: { _skip: true, _msg: 'All ' + items.length + ' leads already exist in Airtable' } }];
return newLeads;

const allLeads = $input.all().map(i => i.json);
if (allLeads[0]?._skip) return [{ json: { _skip: true, _msg: allLeads[0]._msg, allLeads: [] } }];

const BATCH_SIZE = 10;
const batches = [];
for (let i = 0; i < allLeads.length; i += BATCH_SIZE) {
  batches.push(allLeads.slice(i, i + BATCH_SIZE));
}

const promptBase = `You are a lead qualification analyst for Casas de Lisboa (CL), an AI-powered marketing service for real estate developers and investors in Portugal.

TARGET CLIENTS: Property developers (promotores imobiliários), real estate investors, construction companies building residential/commercial projects in Portugal.

NOT TARGET: Real estate agents/brokers, mediators, consultants, PropTech SaaS, HR managers, IT directors, or anyone not directly developing/investing in property.

For EACH lead, evaluate:
1. FIT_SCORE (0-100): How well they match the target profile
   - Is developer/investor/construction (not broker/agent)? +40
   - C-level or decision maker? +20
   - Based in Portugal (Lisboa/Porto/Algarve)? +15
   - Active on LinkedIn (>2000 connections)? +10
   - Has company website? +5
   - Years of experience >10? +10
2. FIT_CLASS: A (>=70), B (40-69), C (<40)
3. FIT_TYPE: developer, investor, construction, broker_agent, other
4. CONNECTION_MSG: Max 280 chars, in ENGLISH. Personalized based on their headline/company. Reference something specific. Tone: insider/systems, no hype. CTA: offer a free digital presence analysis for their developments.
5. FOLLOWUP_MSG: Max 500 chars, in ENGLISH. Value proposition + soft CTA. Mention how AI-powered marketing helps sell developments faster.
6. REJECT_REASON: If class C, explain why (e.g. "broker not developer", "wrong industry")

RESPOND ONLY valid JSON array, no markdown:
[{"index":0,"fitScore":85,"fitClass":"A","fitType":"developer","connectionMsg":"msg","followupMsg":"msg","rejectReason":""}]

DATA:
`;

return batches.map((batch, idx) => ({
  json: {
    prompt: promptBase + JSON.stringify(batch, null, 2),
    leadsCount: batch.length,
    batchIndex: idx,
    totalBatches: batches.length,
    batchLeads: batch,
    allLeads: allLeads
  }
}));

const claudeResponses = $input.all();
const allLeads = $('Prepare Claude Payload').first().json.allLeads;
const weekLabel = allLeads[0]?.weekLabel || '';
const runDate = allLeads[0]?.runDate || new Date().toISOString();

let allScores = [];
for (const resp of claudeResponses) {
  try {
    const raw = resp.json.content?.[0]?.text || resp.json.output || resp.json.result || JSON.stringify(resp.json);
    const jsonMatch = raw.match(/\[[\s\S]*\]/);
    if (jsonMatch) allScores = allScores.concat(JSON.parse(jsonMatch[0]));
  } catch (e) {}
}

const results = [];
for (let i = 0; i < allLeads.length; i++) {
  const lead = allLeads[i];
  const score = allScores[i] || { fitScore: 30, fitClass: 'C', fitType: 'other', connectionMsg: '', followupMsg: '', rejectReason: 'Claude parse error' };

  results.push({ json: {
    nome: lead.nome,
    headline: lead.headline,
    empresa: lead.empresa,
    cargo: lead.cargo,
    linkedinUrl: lead.linkedinUrl,
    companyUrl: lead.companyUrl,
    location: lead.location,
    connections: lead.connections,
    followers: lead.followers,
    website: lead.website,
    about: lead.about,
    fitScore: score.fitScore || 30,
    fitClass: score.fitClass || 'C',
    fitType: score.fitType || 'other',
    connectionMsg: score.connectionMsg || '',
    followupMsg: score.followupMsg || '',
    rejectReason: score.rejectReason || '',
    status: 'Novo',
    source: 'LinkedIn',
    weekLabel: weekLabel,
    runDate: runDate
  }});
}

return results.filter(r => r.json.fitClass !== 'C' && r.json.fitType !== 'broker_agent');

const allLeads = $('Parse Claude + Filter').all().map(i => i.json);

const scoreA = allLeads.filter(l => l.fitClass === 'A');
const scoreB = allLeads.filter(l => l.fitClass === 'B');
const developers = allLeads.filter(l => l.fitType === 'developer');
const investors = allLeads.filter(l => l.fitType === 'investor');

const topLeads = scoreA
  .sort((a, b) => (b.fitScore || 0) - (a.fitScore || 0))
  .slice(0, 5)
  .map(l => `  \u2022 ${l.nome} (${l.fitScore}) \u2014 ${l.empresa} [${l.fitType}]`)
  .join('\n');

const weekLabel = allLeads[0]?.weekLabel || 'W??';
const location = $('Location Rotation').first().json.location || '??';

const message = `\ud83c\udfe2 Lead Gen CL \u2014 ${weekLabel} (${location})\n\nTotal qualified: ${allLeads.length}\nScore A: ${scoreA.length} | Score B: ${scoreB.length}\nDevelopers: ${developers.length} | Investors: ${investors.length}\n\n\ud83c\udfc6 Top 5:\n${topLeads || 'None'}\n\n\ud83d\udcca Airtable: https://airtable.com/appHlW68vIgSzS8BX/tblfEtNAVuXRZdxW9`;

return [{ json: { message, totalLeads: allLeads.length, scoreA: scoreA.length, scoreB: scoreB.length } }];

const message = $('Aggregate Stats').first().json.message;

let text = message
  .replace(/\*\*(.*?)\*\*/g, '*$1*')
  .replace(/^- /gm, '• ')
  .replace(/---/g, '───');

if (text.length > 4000) {
  text = text.substring(0, 3950) + '\n\n(truncado)';
}

return [{ json: { text, number: '351913095597' } }];

